  ('disabled-64311456-moex-00276', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政機關管轄之敘述，下列何者正確？', '["管轄權非依法規不得設定或變更", "行政機關得將其權限委託所屬下級機關執行之", "行政機關因法規變更而喪失管轄權時，應將案件移送有管轄權之機關， 無須通知當事人", "同一事件，數行政機關均有管轄權者，逕由各該機關協議定管轄權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
