  ('disabled-64311456-moex-00278', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依公務員服務法規定，關於公務員對於長官所發命令之應對，下列敘述何 者錯誤？', '["公務員對於直接上級及更上級長官同時所發命令，以直接上級長官之命 令為準", "長官就其監督範圍以外事項所發命令，屬官仍有服從之義務", "屬官對於長官所發命令，如有意見，得隨時陳述", "主管長官與兼管長官同時所發命令，以主管長官之命令為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00279', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於公務員懲戒處分之敘述，下列何者正確？', '["撤職，撤其現職，並於一定期間停止任用", "休職，休其現職，停發俸給，但得申請退休", "減俸，依受懲戒人現職之月俸減10%至30%支給", "罰款，其金額為新臺幣2萬元以上、2百萬元以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00280', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於公務人員保障事件之再審議，下列敘述何者正確？', '["申請再審議應於20日之不變期間內為之", "再審議之申請，自復審決定或再申訴決定確定時起，如逾5年者，不得 提起", "再審議無理由者，應為不受理之決定", "再審議之申請，於作成再審議決定前不得撤回"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00281', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於公務人員對於服務機關所為之行政處分，認為違法或顯然不當，致損 害其權利或利益之救濟，下列敘述何者正確？', '["應向原處分機關之直接上級機關提起復審", "提起復審應於收受行政處分書之次日起2個月內提起", "復審人如不服復審決定，得於決定書送達之次日起 30 日內，向保訓會 提起訴願", "原行政處分不因依公務人員保障法所進行之各項程序而停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00282', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依公務人員任用法任用為公務人員之情事，下列何者錯誤？', '["褫奪公權尚未復權", "犯詐欺取財罪，受緩刑宣告", "曾受免除職務懲戒處分", "受監護或輔助宣告，尚未撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00283', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於公務員服務法就公務員離職後利益迴避之旋轉門條款規定，下列敘述 何者錯誤？', '["適用之對象包括政務人員在內", "公務員受此條款限制之期間為離職後3年內", "不得擔任與其離職前5年內之職務直接相關之非營利事業董事、監察人", "違反此規定者應受刑事處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00284', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於公物與公共設施之敘述，下列何者錯誤？', '["由行政機關管理且直接供公共或公務目的使用者，屬於公共設施", "公共設施亦得屬於私人所有", "地方議會之議場具有行政使用公物之性質，直接供一般公共使用", "地方議會非屬學理上所稱之營造物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
